SELECT count(distinct ced_outer.value) AS totalSamples FROM clinical_event_data ced_outer RIGHT JOIN clinical_event ce_outer ON ced_outer.clinical_event_id = ce_outer.clinical_event_id JOIN patient p_outer ON ce_outer.patient_id = p_outer.internal_id JOIN cancer_study cs_outer ON p_outer.cancer_study_id = cs_outer.cancer_study_id
cs_outer.cancer_study_identifier IN
#{studyId}
AND
(LOWER(ce_outer.event_type) = 'sample acquisition' OR LOWER(ce_outer.event_type) = 'specimen') AND ced_outer.`key` = 'SAMPLE_ID' AND concat(cs_outer.cancer_study_identifier, '_', ced_outer.value) IN ( ) AND concat(cs_outer.cancer_study_identifier, '_', p_outer.stable_id) IN ( SELECT DISTINCT concat(cs_inner.cancer_study_identifier, '_', p_inner.stable_id) FROM clinical_event_data ced_inner RIGHT JOIN clinical_event ce_inner ON ced_inner.clinical_event_id = ce_inner.clinical_event_id JOIN patient p_inner ON ce_inner.patient_id = p_inner.internal_id JOIN cancer_study cs_inner ON p_inner.cancer_study_id = cs_inner.cancer_study_id
cs_inner.cancer_study_identifier IN
#{studyId}
AND
lower(ce_inner.event_type) = 'treatment' AND ced_inner.`key` = 'AGENT' AND concat(cs_inner.cancer_study_identifier, '_', p_inner.stable_id) in ( SELECT patient_unique_id FROM sample_derived
sample_unique_id IN ()
)
)
